module top_module(A, B, sub, CK, Y, Cout);input [3:0] A, B;
input sub, CK;
output [3:0] Y;
output Cout;
reg [3:0] Y_reg;
wire [3:0] B_neg;
wire [3:0] B_sub;
wire [4:0] Y_add;

// Invert B and add 1 to obtain two's complement of B
assign B_neg = ~B + 1;

// Select either B or B_neg based on sub input
assign B_sub = (sub) ? B_neg : B;

// Add A and B_sub
assign Y_add =  {(1'b1 & 1'b0), A} + {1'b0, B_sub};

// Register the sum/difference output
always @(posedge CK) begin
    Y_reg <= Y_add[3:0];
end

// Output the sum/difference and carry/borrow
assign Y = Y_reg;
assign Cout = Y_add[4];

endmodule

module top_module(SW, KEY, LEDR);input [1:0] SW;
	input [0:0] KEY;
	output [9:0] LEDR;

	wire Clock, Resetn, w, z;
	reg [3:0] y_Q, Y_D;

	assign Clock = KEY[0];
	assign Resetn = SW[0];
	assign w = SW[1];

	parameter A = 4'b0000, B = 4'b0001, C = 4'b0010, D = 4'b0011, E = 4'b0100,
		F = 4'b0101, G = 4'b0110, H = 4'b0111, I = 4'b1000;

	always @(w, y_Q)
	begin: state_table
		case (y_Q)
			A:	if (!w) Y_D = B;
				else Y_D = F;
			B:	if (!w) Y_D = C;
				else Y_D = F;
			C:	if (!w) Y_D = D;
				else Y_D = F;
			D:	if (!w) Y_D = E;
				else Y_D = F;
			E:	if (!w) Y_D = E;
				else Y_D = F;
			F:	if (!w) Y_D = B;
				else Y_D = G;
			G:	if (!w) Y_D = B;
				else Y_D = H;
			H:	if (!w) Y_D = B;
				else Y_D = I;
			I:	if (!w) Y_D = B;
				else Y_D = I;
			default: Y_D = 4'bxxxx;
		endcase
	end 

	always @(posedge Clock)
		if (Resetn  == 1'b0)	
			y_Q <= A;
