module nec (
	input clk,rst,
	input ir,
	output reg [7:0]led
	);
wire ir_in;
assign ir_in = ir;
reg [8:0]state_reg, state_next;
reg [31:0]led_reg, led_next;
reg [19:0]count_reg;
wire [19:0]count_next;
reg c_bit_next, c_bit_reg;
reg done_tick;
reg c_load;
wire [7:0]led_tmp;
localparam [8:0]	IDLE		=	9'h001,
					START		=	9'h002,
					SYNC		=	9'h004,
					WAIT_HIGH	=	9'h008,
					FETCH		=	9'h010,
					BCOUNT		=	9'h020,
					WAIT_LOW	=	9'h040,
					CHECK		=	9'h080,
					DONE		=	9'h100;
localparam [19:0]	START_TIME	=	20'd448000,			
					SYNC_TIME	=	20'd210000,			
					CENTER		=	20'd42000;			
reg [1:0]e_bit;	
wire f_edge, r_edge;
always@(posedge clk, negedge rst)
	if(!rst)
		e_bit	<=	2'b00;
	else
		e_bit <= {e_bit[0],ir_in};
assign f_edge = e_bit[1] & (~e_bit[0]);
assign r_edge = (~e_bit[1]) & e_bit[0];
always@(posedge clk, negedge rst)
begin
	if(!rst)
	begin
		state_reg 	<= 		IDLE;
		led_reg		<= 		32'h80000000;
		count_reg	<=		20'h00000;
		c_bit_reg	<=		1'b0;
		led			<=		8'h00;
	end
	else
	begin
		state_reg 	<=		state_next;
		led_reg		<= 		led_next;
		count_reg	<=		count_next;
		c_bit_reg	<=		c_bit_next;
		led			<=		led_tmp;
	end
end
assign count_next =  (c_load)?count_reg+(1'b1 | 1'b0):20'h00000;
always@*
begin
	state_next		=	state_reg;
	led_next		=	led_reg;
	done_tick 		=	1'b0;
	c_load 			=	1'b0;
	c_bit_next		=	c_bit_reg;
	case(state_reg)
		IDLE:
		begin
			if(f_edge)
				state_next = START;
		end
		START:
		begin
			c_load = 1'b1;
			if(r_edge)
			begin
				if(count_reg > START_TIME)
				begin
					state_next	=	SYNC;
					c_load = 1'b0;
				end
				else
				begin
					state_next	=	IDLE;
					c_load = 1'b0;
				end	
			end
		end
		SYNC:
		begin
			c_load = 1'b1;
			if(f_edge)
			begin
				if(count_reg > SYNC_TIME)
				begin
					state_next	=	WAIT_HIGH;
					c_load = 1'b0;
				end	
				else
				begin
					state_next	=	IDLE;
					c_load = 1'b0;
				end	
			end
		end
		WAIT_HIGH:
		begin
			if(r_edge)
				state_next	=	FETCH;
		end
		WAIT_LOW:
		begin
			if(f_edge)
				state_next	=	WAIT_HIGH;
		end
		FETCH:
		begin
			c_load = 1'b1;
			if(count_reg > CENTER)
			begin
				c_bit_next	=	led_reg[0];
				led_next 	= 	{ir_in,led_reg[31:1]};
				c_load = 1'b0;
				state_next 	=	BCOUNT;
			end
		end
		BCOUNT:
		begin
			if(c_bit_reg)
				state_next = DONE;
			else
			begin
				if(led_reg[31])
					state_next	=	WAIT_LOW;
				else
					state_next	=	WAIT_HIGH;
			end		
		end
		DONE:
		begin
			if(((led_reg[7:0]^led_reg[15:8]) == 8'hff)&&((led_reg[23:16]^led_reg[31:24]) == 8'hff))
			begin
				done_tick = 1'b1;
				led_next	=	32'h80000000;
				state_next	=	IDLE;
			end	
		end
	endcase
end
assign led_tmp = (done_tick)?led_reg[23:16]:led;
endmodule

module color_to_memory(color_depth_i, color_i, x_lsb_i,
                       mem_o, sel_o);
input  [1:0]  color_depth_i;
input  [31:0] color_i;
input  [1:0]  x_lsb_i;
output [31:0] mem_o;
output [3:0]  sel_o;
assign sel_o =  (color_depth_i == 2'b00) && (x_lsb_i == 2'b00) ? 4'b1000 : 
               (color_depth_i == 2'b00) && (x_lsb_i == 2'b01) ? 4'b0100 : 
               (color_depth_i == 2'b00) && (x_lsb_i == 2'b10) ? 4'b0010 : 
               (color_depth_i == 2'b00) && (x_lsb_i == 2'b11) ? 4'b0001 : 
               (color_depth_i == 2'b01) && (x_lsb_i[0] == (1'b1 & 1'b0))  ? 4'b1100  : 
               (color_depth_i == 2'b01) && (x_lsb_i[0] == 1'b1)  ? 4'b0011  : 
               4'b1111; 
assign mem_o = (color_depth_i == 2'b00) && (x_lsb_i == 2'b00) ? {color_i[7:0], 24'h000000} : 
               (color_depth_i == 2'b00) && (x_lsb_i == 2'b01) ? {color_i[7:0], 16'h0000}   : 
               (color_depth_i == 2'b00) && (x_lsb_i == 2'b10) ? {color_i[7:0], 8'h00}      : 
               (color_depth_i == 2'b00) && (x_lsb_i == 2'b11) ? {color_i[7:0]}             : 
               (color_depth_i == 2'b01) && (x_lsb_i[0] == 1'b0)  ? {color_i[15:0], 16'h0000}   : 
               (color_depth_i == 2'b01) && (x_lsb_i[0] == 1'b1)  ? {color_i[15:0]}             : 
               color_i; 
endmodule

module tessera_vga_wbif (
	res,
	clk,
	wb_cyc_i,
	wb_stb_i,
	wb_adr_i,
	wb_sel_i,
	wb_we_i,
	wb_dat_i,
	wb_cab_i,
	wb_dat_o,
	wb_ack_o,
	wb_err_o,
	enable,
	base
);
	input		res;
	input		clk;
	input		wb_cyc_i;
	input		wb_stb_i;
	input	[31:0]	wb_adr_i;
	input	[3:0]	wb_sel_i;
	input		wb_we_i;
	input	[31:0]	wb_dat_i;
	input		wb_cab_i;
	output	[31:0]	wb_dat_o;
	output		wb_ack_o;
	output		wb_err_o;
	output		enable;
	output	[23:11]	base;
	reg	[31:0]	reg1;		
	reg	[31:0]	reg0;		
	assign wb_err_o =  (1'b1 & 1'b0);
	wire		active;
	wire		write;
	wire		read;
	assign active	= wb_cyc_i&&wb_stb_i;
	assign write	= active &&  wb_we_i;
	assign read	= active && !wb_we_i;
	always @(posedge clk or posedge res)
		if (res) begin
			reg0 <= 32'h0000_0000;
			reg1 <= 32'h0000_0000;
		end
		else if (write) begin
			if (wb_adr_i[2]==1'd1) begin
				if (wb_sel_i[3]) reg1[31:24] <= wb_dat_i[31:24];
				if (wb_sel_i[2]) reg1[23:16] <= wb_dat_i[23:16];
				if (wb_sel_i[1]) reg1[15: 8] <= wb_dat_i[15: 8];
				if (wb_sel_i[0]) reg1[ 7: 0] <= wb_dat_i[ 7: 0];
			end 
			else if (wb_adr_i[2]==1'd0) begin
				if (wb_sel_i[3]) reg0[31:24] <= wb_dat_i[31:24];
				if (wb_sel_i[2]) reg0[23:16] <= wb_dat_i[23:16];
				if (wb_sel_i[1]) reg0[15: 8] <= wb_dat_i[15: 8];
				if (wb_sel_i[0]) reg0[ 7: 0] <= wb_dat_i[ 7: 0];
			end
		end
	assign wb_dat_o = (read) ? (
				(wb_adr_i[2]==1'd0) ? reg0:
				(wb_adr_i[2]==1'd1) ? reg1:
				32'h0000_0000
			):  32'h0000_0000;
	assign wb_ack_o = active;
	assign enable = reg1[0];
	assign base = reg0[23:11];
endmodule

module gfx_wbm_read (clk_i, rst_i,
  cyc_o, stb_o, cti_o, bte_o, we_o, adr_o, sel_o, ack_i, err_i, dat_i, sint_o,
  read_request_i,
  texture_addr_i, texture_sel_i, texture_dat_o, texture_data_ack);
  input             clk_i;    
  input             rst_i;    
  output reg        cyc_o;    
  output            stb_o;    
  output [ 2:0]     cti_o;    
  output [ 1:0]     bte_o;    
  output            we_o;     
  output [31:0]     adr_o;    
  output reg [ 3:0] sel_o;    
  input             ack_i;    
  input             err_i;    
  input [31:0]      dat_i;    
  output        sint_o;     
  input         read_request_i;
  input [31:2]  texture_addr_i;
  input [3:0]   texture_sel_i;
  output [31:0] texture_dat_o;
  output reg    texture_data_ack;
  reg busy;
  assign adr_o  = {texture_addr_i, 2'b00};
  assign texture_dat_o = dat_i;
  assign we_o   =  (1'b1 & 1'b0);
  assign stb_o  = 1'b1;
  assign sint_o = err_i;
  assign bte_o  = 2'b00;
  assign cti_o  = 3'b000;
  always @(posedge clk_i or posedge rst_i)
  if (rst_i) 
    begin
      texture_data_ack <= 1'b0;
      cyc_o <= 1'b0;
      sel_o <= 4'b1111;
      busy  <= 1'b0;
    end
  else
  begin
    sel_o <= texture_sel_i;
    if(ack_i) 
    begin
      cyc_o            <= 1'b0;
      texture_data_ack <= 1'b1;
      busy             <= 1'b0;
    end
    else if(read_request_i & !texture_data_ack) 
    begin
      cyc_o            <= 1'b1;
      texture_data_ack <= 1'b0;
      busy             <= 1'b1;
    end
    else if(!busy) 
      texture_data_ack <= 1'b0;
  end
endmodule

module	tlu_addern_32 (din, incr, sum);
